2	
3	import (
4		"fmt"
5		"os"
6		"path/filepath"
7		"sort"
8		"strings"
9	
10		"github.com/partio-io/cli/internal/agent"
11	)
12	
13	// FindLatestJSONLPath returns the path of the most recently modified JSONL file
14	// without parsing its contents. This is cheaper than FindLatestSession.
15	func (d *Detector) FindLatestJSONLPath(repoRoot string) (string, error) {
16		sessionDir, err := d.FindSessionDir(repoRoot)
17		if err != nil {
18			return "", err
19		}
20	
21		entries, err := os.ReadDir(sessionDir)
22		if err != nil {
23			return "", fmt.Errorf("reading session directory: %w", err)
24		}
25	
26		var jsonlFiles []os.DirEntry
27		for _, e := range entries {
28			if !e.IsDir() && strings.HasSuffix(e.Name(), ".jsonl") {
29				jsonlFiles = append(jsonlFiles, e)
30			}
31		}
32	
33		if len(jsonlFiles) == 0 {
34			return "", fmt.Errorf("no JSONL session files found in %s", sessionDir)
35		}
36	
37		sort.Slice(jsonlFiles, func(i, j int) bool {
38			ii, _ := jsonlFiles[i].Info()
39			jj, _ := jsonlFiles[j].Info()
40			return ii.ModTime().After(jj.ModTime())
41		})
42	
43		return filepath.Join(sessionDir, jsonlFiles[0].Name()), nil
44	}
45	
46	// FindLatestSession finds the most recently modified JSONL session file.
47	func (d *Detector) FindLatestSession(repoRoot string) (string, *agent.SessionData, error) {
48		latestPath, err := d.FindLatestJSONLPath(repoRoot)
49		if err != nil {
50			return "", nil, err
51		}
52	
53		// Parse the JSONL file
54		data, err := ParseJSONL(latestPath)
55		if err != nil {
56			return latestPath, nil, fmt.Errorf("parsing JSONL: %w", err)
57		}
58	
59		return latestPath, data, nil
60	}
