package hooks

import (
	"encoding/json"
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
	"time"

	"github.com/partio-io/cli/internal/agent"
	"github.com/partio-io/cli/internal/agent/claude"
	"github.com/partio-io/cli/internal/attribution"
	"github.com/partio-io/cli/internal/checkpoint"
